def main():
    if not pathlib.Path("lib/portrait-engine").is_dir():
        print("ERROR: Run this from the petprintsstudio repo root.")
        print("  cd ~/petprintsstudio && python3 patch_multi_subject_engine.py")
        sys.exit(1)

    for path, b64 in FILES.items():
        content = base64.b64decode(b64.replace("\n", "").encode("ascii")).decode("utf-8")
        p = pathlib.Path(path)
        before = len(p.read_text()) if p.exists() else 0
        p.write_text(content)
        print(f"  wrote {path}  ({before} -> {len(content)} chars)")

    print("\nAll 3 files written. Next:")
    print("  npm run build")
    print("  git add -A")
    print("  git commit -m 'Multi-subject portrait engine: per-subject identity, arrangement preservation, style-parity directives, kill switch'")
    print("  git push")

if __name__ == "__main__":
    main()
